if (!msg.payload || typeof msg.payload !== "object") {
  return null;
}

const latest = msg.payload;
const history = global.get("tempHistory") || [];

history.push({
  ts: latest.ts,
  temp_c: Number(latest.temp_c)
});

if (history.length > 60) {
  history.shift();
}

global.set("latestTelemetry", latest);
global.set("tempHistory", history);

return msg;

const latest = global.get("latestTelemetry") || null;
const history = global.get("tempHistory") || [];

const safe = (value) => String(value ?? "").replace(/[&<>"']/g, (ch) => ({
  '&': '&amp;',
  '<': '&lt;',
  '>': '&gt;',
  '\"': '&quot;',
  "'": '&#39;'
}[ch]));

let chart = '<p>No telemetry yet.</p>';
if (history.length > 0) {
  const temps = history.map((p) => Number(p.temp_c));
  const min = Math.min(...temps);
  const max = Math.max(...temps);
  const span = (max - min) || 1;
  const width = 700;
  const height = 220;

  const points = history.map((p, idx) => {
    const x = Math.round((idx / Math.max(history.length - 1, 1)) * width);
    const y = Math.round(height - ((Number(p.temp_c) - min) / span) * height);
    return `${x},${y}`;
  }).join(' ');

  chart = `<svg viewBox="0 0 ${width} ${height}" width="100%" height="220" style="border:1px solid #ccc;background:#fff"><polyline fill="none" stroke="#1976d2" stroke-width="2" points="${points}" /></svg><p>Range: ${min.toFixed(2)}°C to ${max.toFixed(2)}°C</p>`;
}

const latestHtml = latest
  ? `<pre>${safe(JSON.stringify(latest, null, 2))}</pre>`
  : '<p>No telemetry yet.</p>';

msg.headers = {
  'Content-Type': 'text/html; charset=utf-8'
};

msg.payload = `<!doctype html><html><head><meta charset="utf-8" /><title>Node-RED MQTT Hello</title><meta name="viewport" content="width=device-width, initial-scale=1" /></head><body style="font-family:Arial,Helvetica,sans-serif;margin:20px;max-width:900px"><h1>MQTT Hello World Dashboard</h1><p>Topic: <code>devices/+/telemetry</code></p><h2>Latest message</h2>${latestHtml}<h2>Temperature chart (last ${history.length} points)</h2>${chart}</body></html>`;

return msg;
